  "lessonText": "Explore essential game development concepts through interactive flashcards.",
  "data": {
    "cards": [
      {
        "front": "What is a game engine?",
        "back": "A software framework designed for the development of video games."
      },
      {
        "front": "What does FPS stand for?",
        "back": "Frames Per Second, a measure of how many unique consecutive images a computer can produce in one second."
      },
      {
        "front": "What is game physics?",
        "back": "The simulation of physical systems in a game to create realistic movements and interactions."
      },
      {
        "front": "What is a sprite?",
        "back": "A two-dimensional image or animation that is integrated into a larger scene."
      }
    ]
  }
}
